  const translateVideo = async () => {
    try {
      setIsTranslating(true);

      // Daten für die API-Anfrage
      const requestData = {
        source_language: sourceLang,
        target_language: targetLang,
        video_url: window.location.href // Aktuelle YouTube-URL
      };

      // Kommunikation mit Python-Backend über fetch-API
      const response = await fetch('http://localhost:5000/translate', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(requestData)
      });

      const result = await response.json();

      // Behandlung des Antwortdaten vom Backend
      if (result.status === 'success') {
        console.log('Übersetzung abgeschlossen:', result.translation);
      }
    } catch (error) {
      console.error('Fehler bei der Übersetzung:', error);
    } finally {
      setIsTranslating(false);
    }
  };

  return (
    <div className="polyglott-voice-container">
      {/* Sprachauswahlliste */}
      <select 
        value={sourceLang} 
        onChange={(e) => setSourceLang(e.target.value)}
        className="language-select"
      >
        <option value="de">Deutsch</option>
        <option value="en">Englisch</option>
        <option value="fr">Französisch</option>
        <option value="es">Spanisch</option>
      </select>

      <select 
        value={targetLang} 
        onChange={(e) => setTargetLang(e.target.value)}
        className="language-select"
      >
        <option value="de">Deutsch</option>
        <option value="en">Englisch</option>
        <option value="fr">Französisch</option>
        <option value="es">Spanisch</option>
      </select>

      {/* Start-Button für Übersetzung */}
      <button 
        onClick={translateVideo}
        disabled={isTranslating}
        className="translate-button"
      >
        {isTranslating ? 'Übersetze...' : 'Übersetzen'}
      </button>
    </div>
  );
};

export default PolyglottVoice;
