// Inject button and dropdown
const injectControls = () => {
  const pipButton = document.querySelector('button[aria-label="Picture-in-Picture"]');
  if (!pipButton || document.getElementById('translator-button')) return;

  const container = pipButton.parentElement;

  // Create translator button
  const button = document.createElement('button');
  button.id = 'translator-button';
  button.innerHTML = '🌐';
  button.style.marginLeft = '8px';
  button.addEventListener('click', () => {
    chrome.runtime.sendMessage({
      action: 'translate',
      videoId: new URLSearchParams(window.location.search).get('v')
    });
  });

  // Create language dropdown
  const select = document.createElement('select');
  select.id = 'language-select';
  select.innerHTML = `
    <option value="en">English</option>
    <option value="es">Spanish</option>
    <option value="fr">French</option>
  `;
  select.style.marginLeft = '8px';

  container.appendChild(select);
  container.appendChild(button);
};

// Wait for YouTube player to load
const observer = new MutationObserver(() => {
  injectControls();
});
observer.observe(document.body, { childList: true, subtree: true });
injectControls();
